export function ASYNC_OK<T>(data: T): AsyncSuccess<T>;
export function ASYNC_OK<T, F extends string>(
  field: F,
  data: T
): AsyncSuccess<T, F>;
export function ASYNC_OK<T, F extends string>(
  fieldOrData: F | T,
  data?: T
): AsyncSuccess<T, F> {
