type OperatorFilterValue = { startsWith: string };

type FilterValue = SimpleFilterValue | OperatorFilterValue;

type Filter = NumberFilter | StringFilter | BooleanFilter | NullFilter;

type NumberFilter = {
  key: string;
  operator: ":";
  value: number;
