};

const formatFilterKey = (key: string, nestedKey?: string) => {
  if (nestedKey) {
    return `${key}[${quote(nestedKey)}]`;
  }
  return key;
};

const isStringEmpty = (value: string) => {
  return !value || value.toString().trim() === "";
