 * falls back to JSON.stringify() (which uses double-quotes) when necessary.
 */
export function quote(input: unknown): string {
  const result = JSON.stringify(input);
  if (typeof input !== "string") {
    return result;
  }

  if (result.includes("'")) {
    return result;
