    while (i <= nextEnd) {
      liveList.insert(deepLiveify(next[i]) as T, i);
      //                                   ^^^^ FIXME Not entirely true
      i++;
    }
    let localI = i;
    while (localI <= prevEnd) {
      liveList.delete(i);
      localI++;
